from dataclasses import dataclass
from datetime import date

@dataclass
class HotReviewChecklist:
    """T+7 review: stability and adoption only."""
    integration_name: str
    launch_date: date
    review_date: date

    # Error and latency
    api_error_rate_pct: float          # target < 1%
    p99_latency_ms: float              # target < pre-launch baseline + 20%
    baseline_latency_ms: float

    # Model behaviour
    unexpected_refusal_count: int      # refusals on content that should be permitted
    safety_filter_trigger_rate_pct: float  # should be consistent with staging observations

    # Adoption
    daily_active_users: int
    adoption_target_users: int

    def latency_regression(self) -> bool:
        threshold = self.baseline_latency_ms * 1.20
        return self.p99_latency_ms > threshold

    def adoption_gap(self) -> float:
        if self.adoption_target_users == 0:
            return 0.0
        return 1.0 - (self.daily_active_users / self.adoption_target_users)

    def status(self) -> str:
        issues = []
        if self.api_error_rate_pct >= 1.0:
            issues.append(f"error rate {self.api_error_rate_pct:.1f}% exceeds 1% threshold")
        if self.latency_regression():
            issues.append(f"p99 latency {self.p99_latency_ms:.0f}ms exceeds baseline + 20%")
        if self.unexpected_refusal_count > 0:
            issues.append(f"{self.unexpected_refusal_count} unexpected refusals — review system prompt")
        if self.adoption_gap() > 0.5:
            issues.append(f"adoption {self.adoption_gap():.0%} below target — investigate discovery or UX")
        if issues:
            return "NEEDS ACTION: " + "; ".join(issues)
        return "STABLE: proceed to T+30 review"

from dataclasses import dataclass, field
from datetime import date

@dataclass
class StandardReviewSnapshot:
    """T+30 quality and user impact review data."""
    integration_name: str
    period_start: date
    period_end: date

    total_interactions: int
    rated_interactions: int
    positive_ratings: int
    negative_ratings: int
    regeneration_events: int
    support_tickets_filed: int
    unique_active_users: int

    cost_per_interaction_actual: float
    cost_per_interaction_estimate: float

    def positive_rate(self) -> float:
        total = self.positive_ratings + self.negative_ratings
        return self.positive_ratings / total if total > 0 else 0.0

    def regeneration_rate(self) -> float:
        return self.regeneration_events / self.total_interactions if self.total_interactions > 0 else 0.0

    def support_ticket_rate(self) -> float:
        return self.support_tickets_filed / self.unique_active_users if self.unique_active_users > 0 else 0.0

    def cost_variance(self) -> float:
        """Positive means over estimate."""
        if self.cost_per_interaction_estimate == 0:
            return 0.0
        return (self.cost_per_interaction_actual - self.cost_per_interaction_estimate) / self.cost_per_interaction_estimate

    def review_summary(self) -> list[str]:
        items = []
        if self.positive_rate() < 0.75:
            items.append(f"QUALITY: positive rate {self.positive_rate():.0%} below 75% target")
        if self.regeneration_rate() > 0.15:
            items.append(f"QUALITY: regeneration rate {self.regeneration_rate():.0%} above 15% threshold")
        if self.support_ticket_rate() > 0.02:
            items.append(f"SUPPORT: ticket rate {self.support_ticket_rate():.1%} above 2% threshold")
        if self.cost_variance() > 0.2:
            items.append(f"COST: actual cost {self.cost_variance():.0%} above estimate — review token usage")
        if not items:
            items.append("ALL METRICS IN RANGE: feature healthy at T+30")
        return items

from dataclasses import dataclass, field
from enum import Enum

class ReviewType(str, Enum):
    HOT       = "T+7"
    STANDARD  = "T+30"
    QUARTERLY = "T+90"
    STRATEGIC = "T+180"

REVIEW_ATTENDEES: dict[ReviewType, list[str]] = {
    ReviewType.HOT:       ["feature engineer", "on-call SRE", "product manager"],
    ReviewType.STANDARD:  ["feature engineer", "product manager", "data analyst", "design"],
    ReviewType.QUARTERLY: ["product manager", "engineering lead", "data analyst", "product leadership"],
    ReviewType.STRATEGIC: ["product manager", "engineering lead", "product leadership", "executive sponsor"],
}

REVIEW_DURATION_MINUTES: dict[ReviewType, int] = {
    ReviewType.HOT: 30,
    ReviewType.STANDARD: 60,
    ReviewType.QUARTERLY: 90,
    ReviewType.STRATEGIC: 120,
}

@dataclass
class ReviewOutcome:
    review_type: ReviewType
    decision: str    # "continue" | "expand" | "redesign" | "retire"
    action_items: list[str] = field(default_factory=list)
    next_review_date: str = ""
    notes: str = ""

    def is_complete(self) -> bool:
        return bool(self.decision and self.action_items and self.next_review_date)

    def requires_escalation(self) -> bool:
        return self.decision in ("redesign", "retire")
